// CorridorScene — 3D 走廊画廊场景
// Canvas + fogExp2 + 走廊墙壁（地板/天花板/两侧）+ DreamDoor 两侧交替排列
// 相机由外部 scrollRef（GSAP ScrollTrigger 写入）驱动，沿 Z 轴前进 + 指针视差

import { useEffect, useMemo, useRef, type RefObject } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { MeshReflectorMaterial } from "@react-three/drei";
import { EffectComposer, Bloom, Vignette } from "@react-three/postprocessing";
import * as THREE from "three";
import type { Dream } from "@/lib/types";
import { getEmotionByWord } from "@/lib/emotions";
import { useOptionalTexture } from "@/hooks/useOptionalTexture";
import { DreamDoor } from "./DreamDoor";
import { FOG_BASE, mixColor } from "./atmosphere";

const DOOR_SPACING = 4; // 每扇门 z 间距
const DOOR_OFFSET_X = 3; // 门距走廊中轴 x 偏移
const CORRIDOR_HALF_HEIGHT = 3;

/** 尽头文案贴图：一次性绘制（Html 会每帧写 DOM transform——滚动抖动源之一） */
function makeEndTextTexture(): { tex: THREE.CanvasTexture; aspect: number } {
  const S = 2;
  const w = 720;
  const h = 150;
  const canvas = document.createElement("canvas");
  canvas.width = w * S;
  canvas.height = h * S;
  const ctx = canvas.getContext("2d")!;
  ctx.scale(S, S);
  ctx.textAlign = "center";
  ctx.textBaseline = "top";
  ctx.font = '300 44px "ZCOOL XiaoWei", "Noto Serif SC", serif';
  ctx.fillStyle = "rgba(240,238,248,0.8)";
  ctx.fillText("仍 未 发 现 的 梦 境 … …", w / 2, 18);
  ctx.font = '400 15px "JetBrains Mono", ui-monospace, monospace';
  ctx.fillStyle = "rgba(255,255,255,0.28)";
  ctx.fillText("T H E   U N F O U N D   D R E A M S", w / 2, 100);
  const tex = new THREE.CanvasTexture(canvas);
  tex.colorSpace = THREE.SRGBColorSpace;
  tex.anisotropy = 4;
  tex.needsUpdate = true;
  return { tex, aspect: w / h };
}

/**
 * 墙面纵向光衰减贴图：墙脚（近光池/踢脚线）微亮、向上沉入暗部，带噪抖动。
 * 纯色平面墙 = 平板黑墙；一条纵向明暗梯度就是最便宜的「光在墙上」。
 */
function makeWallGradTexture(): THREE.CanvasTexture {
  const w = 64;
  const h = 256;
  const canvas = document.createElement("canvas");
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext("2d")!;
  const g = ctx.createLinearGradient(0, 0, 0, h);
  g.addColorStop(0, "#0a0914"); // 顶部（贴图 v=1 在下……canvas y=0 对应 v=1 即墙顶）
  g.addColorStop(0.62, "#100e1f");
  g.addColorStop(1, "#161329"); // 墙脚微亮
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, w, h);
  const img = ctx.getImageData(0, 0, w, h);
  const px = img.data;
  for (let i = 0; i < px.length; i += 4) {
    const n = (Math.random() - 0.5) * 7;
    px[i] += n;
    px[i + 1] += n;
    px[i + 2] += n;
  }
  ctx.putImageData(img, 0, 0);
  const tex = new THREE.CanvasTexture(canvas);
  tex.colorSpace = THREE.SRGBColorSpace;
  tex.wrapS = THREE.MirroredRepeatWrapping;
  tex.wrapT = THREE.ClampToEdgeWrapping;
  tex.needsUpdate = true;
  return tex;
}

/** 径向柔光贴图（白核→透明），用于走廊尽头的柔和光晕焦点 */
function makeGlowTexture(): THREE.CanvasTexture {
  const size = 256;
  const canvas = document.createElement("canvas");
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext("2d")!;
  const g = ctx.createRadialGradient(size / 2, size / 2, 0, size / 2, size / 2, size / 2);
  g.addColorStop(0, "rgba(255,255,255,1)");
  g.addColorStop(0.45, "rgba(255,255,255,0.35)");
  g.addColorStop(1, "rgba(255,255,255,0)");
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, size, size);
  const tex = new THREE.CanvasTexture(canvas);
  tex.needsUpdate = true;
  return tex;
}

/** 走廊浮尘：沿走廊分布的微光粒子，增加纵深与呼吸感（Bloom 加持出辉光） */
function CorridorDust({ length, color, texture }: { length: number; color: string; texture: THREE.Texture }) {
  const ref = useRef<THREE.Points>(null);
  const matRef = useRef<THREE.PointsMaterial>(null);
  const positions = useMemo(() => {
    const count = 90;
    const arr = new Float32Array(count * 3);
    for (let i = 0; i < count; i++) {
      arr[i * 3] = (Math.random() - 0.5) * 5;
      arr[i * 3 + 1] = (Math.random() - 0.5) * 5;
      arr[i * 3 + 2] = -Math.random() * (length + 10) + 4;
    }
    return arr;
  }, [length]);
  useFrame((state) => {
    if (!ref.current) return;
    const t = state.clock.elapsedTime;
    ref.current.position.y = Math.sin(t * 0.2) * 0.15;
    if (matRef.current) matRef.current.opacity = 0.4 + Math.sin(t * 0.6) * 0.15;
  });
  return (
    <points ref={ref}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} />
      </bufferGeometry>
      <pointsMaterial
        ref={matRef}
        map={texture}
        size={0.08}
        color={color}
        transparent
        opacity={0.6}
        sizeAttenuation
        depthWrite={false}
        blending={THREE.AdditiveBlending}
      />
    </points>
  );
}

/** 走廊墙壁：地板（MeshReflectorMaterial 反射）+ 天花板 + 左右墙 + 远端封口 + 尽头光源 */
function CorridorWalls({ length, accentColor, glowTex, endMist, wallPanel, floorBase, ceilBase }: { length: number; accentColor: string; glowTex: THREE.Texture; endMist: THREE.Texture | null; wallPanel: THREE.Texture | null; floorBase: THREE.Texture | null; ceilBase: THREE.Texture | null }) {
  // 墙体向尽头方向大幅延长：让走廊管道在雾中隐没，而非露出方形开口
  // （之前 +16 会在尽头露出背景色的方形截面——「字的背景像塑料板」的元凶）
  const wallLen = length + 90;
  const centerZ = -length / 2 - 25;
  // 收集本组件 useMemo 创建/克隆的纹理，卸载时统一 dispose 释放 GPU 内存
  // （R3F 不自动 dispose 传给 material 的纹理；glowTex/endMist 由父组件拥有，不在此收集）
  const texturesRef = useRef<THREE.Texture[]>([]);
  const endText = useMemo(() => {
    const r = makeEndTextTexture();
    texturesRef.current.push(r.tex);
    return r;
  }, []);
  // 墙面光衰减贴图：沿墙长镜像平铺（避免噪点被拉成横向条纹）
  const wallGrad = useMemo(() => {
    const t = makeWallGradTexture();
    t.repeat.set(Math.max(wallLen / 8, 1), 1);
    texturesRef.current.push(t);
    return t;
  }, [wallLen]);
  // 护墙板逐墙对齐：瓦片=8 个世界单位（同侧门间距），把门位对到瓦片中心
  // （中心是两块嵌板之间的壁柱位，被门覆盖；嵌板恰好分列门两侧）。
  // 左墙 u 起点在 z=+20 → 门(z=0,-8…)相位恒为 0.5，无需补偿；
  // 右墙 u 起点随走廊长度变化 → 按 length 计算相位差补到 0.5。
  const wallTex = useMemo(() => {
    if (!wallPanel) return { left: null as THREE.Texture | null, right: null as THREE.Texture | null };
    const mk = (offsetX: number) => {
      const t = wallPanel.clone();
      t.wrapS = THREE.RepeatWrapping;
      t.wrapT = THREE.ClampToEdgeWrapping;
      t.repeat.set(wallLen / 8, 1);
      t.offset.x = offsetX;
      t.needsUpdate = true;
      return t;
    };
    // 门要挂在嵌板中央（美术馆挂画逻辑），不能横跨两块板：
    // 瓦片内两块嵌板中心在相位 0.25 / 0.75——把门位相位对到 0.25
    const rightPhase = ((((length + 66) / 8) % 1) + 1) % 1;
    const left = mk(-0.25);
    const right = mk(0.25 - rightPhase);
    if (left) texturesRef.current.push(left);
    if (right) texturesRef.current.push(right);
    return { left, right };
  }, [wallPanel, wallLen, length]);
  // 地板拼花：4×4 世界单位一瓦（纹样放大到肉眼可读）
  const floorTex = useMemo(() => {
    if (!floorBase) return null;
    const t = floorBase.clone();
    t.wrapS = THREE.RepeatWrapping;
    t.wrapT = THREE.RepeatWrapping;
    t.repeat.set(1.5, wallLen / 4);
    t.needsUpdate = true;
    texturesRef.current.push(t);
    return t;
  }, [floorBase, wallLen]);
  // 藻井天花：6×6 世界单位一瓦
  const ceilTex = useMemo(() => {
    if (!ceilBase) return null;
    const t = ceilBase.clone();
    t.wrapS = THREE.RepeatWrapping;
    t.wrapT = THREE.RepeatWrapping;
    t.repeat.set(1, wallLen / 6);
    t.needsUpdate = true;
    texturesRef.current.push(t);
    return t;
  }, [ceilBase, wallLen]);
  // 卸载时释放本组件创建/克隆的纹理 GPU 内存（StrictMode 双调用下 push 重复引用，
  // dispose 幂等安全）
  useEffect(() => {
    return () => {
      for (const t of texturesRef.current) t.dispose();
      texturesRef.current = [];
    };
  }, []);
  return (
    <group>
      {/* 地板：拼花木地板（gpt-image）+ 克制的反射——
          纯色+强模糊反射会读成塑料板；木纹为主、倒影为辅才像打过蜡的美术馆地面 */}
      <mesh position={[0, -CORRIDOR_HALF_HEIGHT, centerZ]} rotation={[-Math.PI / 2, 0, 0]}>
        <planeGeometry args={[6, wallLen]} />
        <MeshReflectorMaterial
          key={floorTex ? "floor-tex" : "floor-plain"}
          blur={[300, 80]}
          resolution={384}
          mixBlur={1}
          mixStrength={floorTex ? 2.2 : 20}
          roughness={floorTex ? 0.92 : 0.85}
          depthScale={1}
          minDepthThreshold={0.4}
          maxDepthThreshold={1.2}
          map={floorTex ?? undefined}
          emissiveMap={floorTex ?? undefined}
          emissive={floorTex ? "#7d76a0" : "#000000"}
          emissiveIntensity={floorTex ? 0.22 : 0}
          color={floorTex ? "#ffffff" : "#0c0b18"}
          metalness={floorTex ? 0.12 : 0.5}
          mirror={floorTex ? 0.12 : 0.4}
        />
      </mesh>
      {/* 天花板：Belle Époque 藻井（gpt-image），缺图回退哑光深色 */}
      <mesh position={[0, CORRIDOR_HALF_HEIGHT, centerZ]} rotation={[Math.PI / 2, 0, 0]}>
        <planeGeometry args={[6, wallLen]} />
        {ceilTex ? (
          <meshStandardMaterial
            map={ceilTex}
            emissiveMap={ceilTex}
            emissive="#494360"
            emissiveIntensity={0.1}
            color="#7d7691"
            metalness={0.05}
            roughness={0.95}
          />
        ) : (
          <meshStandardMaterial color="#0a0913" metalness={0.05} roughness={0.95} />
        )}
      </mesh>
      {/* 左墙：gpt-image 画的 Belle Époque 护墙板（烘焙光/线脚都在图里），
          缺图回退纵向光衰减渐变 */}
      <mesh position={[-DOOR_OFFSET_X, 0, centerZ]} rotation={[0, Math.PI / 2, 0]}>
        <planeGeometry args={[wallLen, 6]} />
        <meshStandardMaterial
          map={wallTex.left ?? wallGrad}
          emissiveMap={wallTex.left ?? wallGrad}
          emissive="#9c92c0"
          emissiveIntensity={0.34}
          color="#ffffff"
          metalness={0.06}
          roughness={0.9}
        />
      </mesh>
      {/* 右墙 */}
      <mesh position={[DOOR_OFFSET_X, 0, centerZ]} rotation={[0, -Math.PI / 2, 0]}>
        <planeGeometry args={[wallLen, 6]} />
        <meshStandardMaterial
          map={wallTex.right ?? wallGrad}
          emissiveMap={wallTex.right ?? wallGrad}
          emissive="#9c92c0"
          emissiveIntensity={0.34}
          color="#ffffff"
          metalness={0.06}
          roughness={0.9}
        />
      </mesh>
      {/* —— 建筑线索：踢脚线 + 天花灯带（透视消失线 = 室内空间感的骨架）——
          墙面的护墙板线脚不用几何拼（几根棍子毫无美感），
          由 gpt-image 画进墙面贴图（wall-panel.png，烘焙光思路） */}
      {/* 左右踢脚线：墙脚微光勾边 */}
      <mesh position={[-DOOR_OFFSET_X + 0.02, -CORRIDOR_HALF_HEIGHT + 0.07, centerZ]}>
        <boxGeometry args={[0.03, 0.14, wallLen]} />
        <meshStandardMaterial color="#232236" metalness={0.5} roughness={0.5} emissive="#8b7fb8" emissiveIntensity={0.2} />
      </mesh>
      <mesh position={[DOOR_OFFSET_X - 0.02, -CORRIDOR_HALF_HEIGHT + 0.07, centerZ]}>
        <boxGeometry args={[0.03, 0.14, wallLen]} />
        <meshStandardMaterial color="#232236" metalness={0.5} roughness={0.5} emissive="#8b7fb8" emissiveIntensity={0.2} />
      </mesh>
      {/* 天花中央灯带：贯穿走廊的细发光线（最强纵深透视线索，Bloom 出柔光） */}
      <mesh position={[0, CORRIDOR_HALF_HEIGHT - 0.02, centerZ]}>
        <boxGeometry args={[0.09, 0.02, wallLen]} />
        <meshBasicMaterial color="#a99cd6" />
      </mesh>
      {/* 尽头不再封口——走廊向未知敞开，想象感来自「纵深」而非一块亮斑 */}
      {/* 尽头引导光源：远处微光 */}
      <pointLight
        position={[0, 0, -length - 5]}
        intensity={1.2}
        color={accentColor}
        distance={12}
        decay={2}
      />
      {/* 光之隧道：柔光在不同深度递减层叠——单块大光晕会读成「一面发光的墙」，
          多层递减才是「光通向更远处」 */}
      {/* 远三层用 gpt-image 迷雾真图（有云絮形状的光才不像亮片），近一层保留情绪色柔光 */}
      {/* 意犹未尽 = 黑暗向深处延续 + 远方一点微光，不是一面亮雾墙——层数收敛、贴脸层删除 */}
      {[
        { z: -length - 6, s: 4.5, o: 0.22, mist: false },
        { z: -length - 13, s: 6.5, o: 0.12, mist: true },
        { z: -length - 22, s: 10, o: 0.06, mist: true },
      ].map((g, i) => (
        <mesh key={i} position={[0, 0, g.z]} scale={[g.s, g.s, 1]}>
          <planeGeometry args={[1, 1]} />
          <meshBasicMaterial
            map={g.mist && endMist ? endMist : glowTex}
            color={g.mist && endMist ? "#ffffff" : accentColor}
            transparent
            opacity={g.o}
            blending={THREE.AdditiveBlending}
            depthWrite={false}
          />
        </mesh>
      ))}
      {/* 幽灵门：尽头之外墙上若隐若现的空门框——尚未成形的梦境，越远越淡 */}
      {/* 幽灵门推到相机停点更远处（-length-4 就是相机终点，贴脸会成大灰板），
          且压得极淡——只该是雾中一丝「似乎还有门」的暗示 */}
      {[0, 1, 2, 3].map((i) => {
        const side = i % 2 === 0 ? -1 : 1;
        const z = -length - 8 - i * 3.4;
        return (
          <mesh
            key={`ghost-${i}`}
            position={[side * (DOOR_OFFSET_X - 0.04), 0, z]}
            rotation={[0, side === -1 ? Math.PI / 2 : -Math.PI / 2, 0]}
          >
            <planeGeometry args={[2.1, 3.1]} />
            <meshBasicMaterial
              color={accentColor}
              transparent
              opacity={0.032 - i * 0.006}
              blending={THREE.AdditiveBlending}
              depthWrite={false}
            />
          </mesh>
        );
      })}
      {/* 尽头文案：canvas sprite（一次绘制零每帧成本），飘在光的深处 */}
      <sprite position={[0, 0.15, -length - 7.5]} scale={[5.6, 5.6 / endText.aspect, 1]}>
        <spriteMaterial map={endText.tex} transparent opacity={0.85} depthWrite={false} />
      </sprite>
    </group>
  );
}

/** 聚焦目标：某扇门的位置与朝向（side=-1 左墙 / +1 右墙） */
export interface FocusTarget {
  x: number;
  z: number;
  side: number;
}

/** 相机轨道：漫游模式读 scrollRef 沿 Z 前进；聚焦模式电影运镜到门前 */
function CameraRig({
  scrollRef,
  length,
  reduceMotion,
  focusTarget,
  diving = false,
}: {
  scrollRef: RefObject<number>;
  length: number;
  reduceMotion: boolean;
  focusTarget: FocusTarget | null;
  diving?: boolean;
}) {
  const { camera } = useThree();
  const startZ = 4;
  const endZ = -length - 4;
  // 聚焦偏心构图的 lookAt z 偏移（damp 过渡，入画俯冲时收回到正对画心）
  const lookZOffRef = useRef(0.9);
  // 入场推镜：挂载时相机从走廊门外(+6)向内滑入——延续碎镜俯冲的前进动量，
  // 「像推开大门走进来」而非黑屏后原地出现
  const introRef = useRef(reduceMotion ? 0 : 6);
  useEffect(() => {
    // 相机接力（真连续穿门）：接管时不瞬移——intro 取「相机当前位置与走廊起点的差」：
    //   · 穿门而来：相机已被门的推进送到 z≈startZ（门槛内），intro≈0，零跳变直接续走
    //   · 深链/直达：相机还在 Canvas 初始位（z≈6），intro≈2，仍有一段「推门而入」滑行
    // fov 不在此瞬切：交给 useFrame 逐帧 damp（50→55 的缓慢变焦，微妙的入廊呼吸感）
    camera.position.x = 0;
    camera.position.y = 0;
    if (!reduceMotion) {
      introRef.current = Math.min(6, Math.max(0, camera.position.z - startZ));
      camera.position.z = startZ + introRef.current;
    } else {
      const cam = camera as THREE.PerspectiveCamera;
      cam.fov = 55;
      cam.updateProjectionMatrix();
      introRef.current = 0;
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  // 注：平滑一律用 damp（帧率无关的指数衰减）。固定系数 lerp 在帧率波动时
  // 平滑量逐帧不同（重场景帧率不稳），叠加 Lenis 自身平滑即产生肉眼可见的滚动抖动。
  useFrame((state, delta) => {
    const dt = Math.min(delta, 0.05); // 掐掉超长帧尖峰，防跳变
    // fov 渐变焦：从门的 50 缓慢张到走廊的 55（穿门后视野徐徐展开，胜过瞬切）
    const cam = camera as THREE.PerspectiveCamera;
    if (cam.isPerspectiveCamera && Math.abs(cam.fov - 55) > 0.01) {
      cam.fov = THREE.MathUtils.damp(cam.fov, 55, 2.2, dt);
      cam.updateProjectionMatrix();
    }
    if (focusTarget) {
      // 聚焦：偏心构图（noomo 编辑式排版）——lookAt 沿走廊方向偏移 0.9，
      // 画作让位到画面一侧，另一侧留白给 DOM 展签（左墙画→画偏右/展签在左，右墙反之）。
      // 入画（diving）：相机向画面俯冲 + lookAt 收回画心，配合页面淡出完成「穿越入画」。
      const camX = focusTarget.side * (DOOR_OFFSET_X - (diving ? 1.05 : 2.7));
      const lookZTarget = diving ? 0 : 0.9;
      const px = reduceMotion || diving ? 0 : state.pointer.x * 0.08;
      const py = reduceMotion || diving ? 0 : state.pointer.y * 0.06;
      if (reduceMotion) {
        lookZOffRef.current = lookZTarget;
        camera.position.set(camX, 0.1, focusTarget.z);
      } else {
        const lam = diving ? 3.2 : 4.5;
        lookZOffRef.current = THREE.MathUtils.damp(lookZOffRef.current, lookZTarget, lam, dt);
        camera.position.x = THREE.MathUtils.damp(camera.position.x, camX + px, lam, dt);
        camera.position.y = THREE.MathUtils.damp(camera.position.y, 0.1 + py, lam, dt);
        camera.position.z = THREE.MathUtils.damp(camera.position.z, focusTarget.z, lam, dt);
      }
      camera.lookAt(focusTarget.x, 0, focusTarget.z + lookZOffRef.current);
      return;
    }
    lookZOffRef.current = 0.9; // 退出聚焦即复位，下次聚焦仍是偏心构图
    const p = Math.max(0, Math.min(1, scrollRef.current ?? 0));
    introRef.current = THREE.MathUtils.damp(introRef.current, 0, 1.7, dt);
    const targetZ = startZ + introRef.current + (endZ - startZ) * p;
    if (reduceMotion) {
      camera.position.z = targetZ;
      camera.position.x = 0;
      camera.position.y = 0;
    } else {
      // 逐画驻足模式：目标 z 是离散停点，lambda 放缓成 ~1.2s 的幕间滑行
      camera.position.z = THREE.MathUtils.damp(camera.position.z, targetZ, 3.4, dt);
      camera.position.x = THREE.MathUtils.damp(camera.position.x, state.pointer.x * 0.45, 3, dt);
      camera.position.y = THREE.MathUtils.damp(camera.position.y, state.pointer.y * 0.25, 3, dt);
    }
    // 朝向跟随相机自身的平滑 z（跟未平滑的 targetZ 会让朝向领先位置，产生微晃）
    camera.lookAt(0, 0, camera.position.z - 8);
  });
  return null;
}

/**
 * 帧率采样：预热后采样，平均帧率确实过低才触发降级回调（卡顿自动降 2.5D，保交付）。
 * 参数必须保守（用户反馈「经常自动跳 2.5D」的根因就是旧参数太激进）：
 * - 预热 4s：穿门抵达后的纹理解码/入场推镜/字体绘制全是掉帧高峰，采样必须避开
 * - 采样 3s + 阈值 22fps：只对「持续真卡」降级，瞬时抖动不触发（降级不可逆，宁纵勿枉）
 * - 连续 2 个低帧窗口才触发（任务4 修复）：单次滑动运镜导致的瞬时掉帧不触发降级，
 *   需要持续 ~6s+ 真实低帧率才会降级——滑动操作再也不会误切 2.5D
 */
function FpsSampler({ onLow }: { onLow?: () => void }) {
  const ref = useRef({ warmUntil: 0, sampleStart: 0, frames: 0, fired: false, lowStreak: 0 });
  useFrame(() => {
    const s = ref.current;
    if (s.fired || !onLow) return;
    const now = performance.now();
    if (s.warmUntil === 0) {
      s.warmUntil = now + 4000; // 首帧：设预热截止，避开加载/入场抖动
      return;
    }
    if (now < s.warmUntil) return;
    if (s.sampleStart === 0) {
      s.sampleStart = now;
      s.frames = 0;
      return;
    }
    s.frames += 1;
    const elapsed = now - s.sampleStart;
    if (elapsed >= 3000) {
      const fps = (s.frames / elapsed) * 1000;
      if (fps < 22) {
        // 低帧窗口：累加连续计数；连续 2 次才触发降级
        s.lowStreak += 1;
        if (s.lowStreak >= 2) {
          s.fired = true;
          onLow();
          return;
        }
      } else {
        // 正常帧窗口：重置连续计数——瞬时掉帧不累积
        s.lowStreak = 0;
      }
      // 开启下一个采样窗口
      s.sampleStart = now;
      s.frames = 0;
    }
  });
  return null;
}

export interface CorridorSceneProps {
  dreams: Dream[];
  onDoorClick: (dream: Dream) => void;
  /** 滚动进度 0-1，由外部 ScrollTrigger 写入 */
  scrollRef: RefObject<number>;
  /** 是否启用 WebGL 雾效（fogShader 降级开关关闭时为 false） */
  withShaderFog: boolean;
  /** prefers-reduced-motion 时禁用平滑 lerp */
  reduceMotion: boolean;
  /** 3D 帧率过低时回调（外部据此降级到 2.5D，保交付） */
  onLowPerformance?: () => void;
  /** 当前聚焦的梦境 id（聚焦模式：相机运镜到该门前，忽略滚动） */
  focusedId?: string | null;
  /** 入画中：相机向聚焦画面俯冲（配合页面淡出过渡） */
  diving?: boolean;
  /** 点击画布空白处（未命中任何门）——外部用于退出聚焦 */
  onMissClick?: () => void;
  /** 独立页模式（默认）：自渲染背景/雾/后处理；单世界 World 统一管理时置 false */
  standalone?: boolean;
  /** 相机控制是否激活（单世界 gate 阶段置 false，交给镜之门运镜） */
  cameraEnabled?: boolean;
  /** 场景整组可见性（单世界 gate 阶段隐藏走廊） */
  visible?: boolean;
}

/**
 * CorridorWorld — 走廊场景内容（不含 Canvas 壳）。
 * 融合单世界 Step1 提取：可作为独立页 Canvas 的孩子（CorridorScene），
 * 也可挂进单世界 World Canvas 与镜之门共存（standalone=false + visible/cameraEnabled 切换）。
 */
export function CorridorWorld({
  dreams,
  onDoorClick,
  scrollRef,
  withShaderFog,
  reduceMotion,
  onLowPerformance,
  focusedId,
  diving = false,
  standalone = true,
  cameraEnabled = true,
  visible = true,
}: Omit<CorridorSceneProps, "onMissClick">) {
  // 最近 20 条，最新在前（走廊入口先看到最新梦境）
  const recent = dreams.slice(-20).reverse();
  const length = Math.max(recent.length - 1, 0) * DOOR_SPACING;
  // 聚焦目标：由 focusedId 求门位（与下方 DreamDoor 排布公式一致）
  const focusIdx = focusedId ? recent.findIndex((d) => d.id === focusedId) : -1;
  const focusTarget: FocusTarget | null =
    focusIdx >= 0
      ? {
          x: (focusIdx % 2 === 0 ? -1 : 1) * DOOR_OFFSET_X,
          z: -focusIdx * DOOR_SPACING,
          side: focusIdx % 2 === 0 ? -1 : 1,
        }
      : null;
  const accentColor =
    getEmotionByWord(recent[0]?.emotion.word ?? "")?.color ?? "#c9b8e8";
  const fogColor = mixColor(FOG_BASE, accentColor, 0.06);
  const fogHex = `#${fogColor.getHexString()}`;
  const glowTex = useMemo(makeGlowTexture, []);
  // 尽头迷雾真图（gpt-image）：缺图回退程序化径向柔光
  const endMist = useOptionalTexture("/textures/corridor-mist.png");
  // 护墙板墙面（gpt-image 烘焙光）：基础纹理，逐墙克隆时再设平铺与相位
  const wallPanel = useOptionalTexture("/textures/wall-panel.png");
  // 拼花木地板（gpt-image 油画质感）：反射材质的底图——纯色模糊反射=塑料感根因
  const floorTexBase = useOptionalTexture("/textures/floor-parquet.png");
  const ceilTexBase = useOptionalTexture("/textures/ceiling-coffer.png");

  return (
    <>
      {standalone && (
        <>
          <color attach="background" args={[fogHex]} />
          {withShaderFog && <fogExp2 attach="fog" args={[fogHex, 0.038]} />}
        </>
      )}
      {/* 场景本体：单世界模式下经 visible 整组显隐（隐藏时灯光/物体均不参与渲染，
          纹理/着色器常驻 GPU——切换零上传成本） */}
      <group visible={visible}>
      {/* 多层光源：环境 + 半球 + 顶光（情绪色）+ 辅光 */}
      <ambientLight intensity={0.42} />
      <hemisphereLight color={accentColor} groundColor={FOG_BASE} intensity={0.34} />
      <pointLight position={[0, 4, 2]} intensity={0.6} color={accentColor} distance={15} />
      <pointLight position={[0, -2, 4]} intensity={0.3} color="#c9b8e8" distance={10} />
      <CorridorWalls length={length} accentColor={accentColor} glowTex={glowTex} endMist={endMist} wallPanel={wallPanel} floorBase={floorTexBase} ceilBase={ceilTexBase} />
      {cameraEnabled && (
        <CameraRig scrollRef={scrollRef} length={length} reduceMotion={reduceMotion} focusTarget={focusTarget} diving={diving} />
      )}
      {!reduceMotion && <CorridorDust length={length} color={accentColor} texture={glowTex} />}
      {/* 帧率采样仅在走廊真正接管后启动（隐藏态的帧率不代表走廊性能） */}
      {!reduceMotion && cameraEnabled && <FpsSampler onLow={onLowPerformance} />}
      {recent.map((d, i) => {
        const side = i % 2 === 0 ? -1 : 1;
        const rotationY = side === -1 ? Math.PI / 2 : -Math.PI / 2;
        const x = side * DOOR_OFFSET_X;
        const z = -i * DOOR_SPACING;
        return (
          <DreamDoor
            key={d.id}
            dream={d}
            position={[x, 0, z]}
            rotationY={rotationY}
            onClick={onDoorClick}
            index={i}
            highlight={focusedId === d.id}
            glowTex={glowTex}
          />
        );
      })}
      </group>
      {/* 后处理：Bloom 让门框辉光与尽头光晕扩散成电影感（单世界模式由 World 统一提供） */}
      {standalone && (
        <EffectComposer>
          <Bloom
            intensity={0.85}
            luminanceThreshold={0.28}
            luminanceSmoothing={0.5}
            mipmapBlur
            radius={0.65}
          />
          {/* 暗角减弱：过重的暗角把走廊四周压成漆黑，吃掉建筑线条的留白层次 */}
          <Vignette eskil={false} offset={0.16} darkness={0.62} />
        </EffectComposer>
      )}
    </>
  );
}

/** 独立 Canvas 壳（单世界 WorldPage 已改用 CorridorWorld；此壳留作独立复用） */
export function CorridorScene({ onMissClick, ...worldProps }: CorridorSceneProps) {
  // dpr 移动端降低，桌面端封顶 1.5
  const dpr: [number, number] =
    typeof window !== "undefined" && window.innerWidth < 768 ? [1, 1.2] : [1, 1.5];
  return (
    <Canvas
      camera={{ position: [0, 0, 4], fov: 55 }}
      dpr={dpr}
      gl={{ antialias: true, alpha: false, powerPreference: "high-performance" }}
      style={{ position: "absolute", inset: 0 }}
      onPointerMissed={() => onMissClick?.()}
    >
      <CorridorWorld {...worldProps} />
    </Canvas>
  );
}
